import os
import hashlib
import secrets
import time
from functools import wraps
from flask import Flask, request, jsonify

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('SECRET_KEY', secrets.token_hex(32))

# In-memory storage (use a database in production)
users_db = {}
tokens_db = {}

TOKEN_EXPIRY_SECONDS = 3600  # 1 hour


def hash_password(password, salt=None):
    """Hash password with salt using SHA-256."""
    if salt is None:
        salt = secrets.token_hex(16)
    hashed = hashlib.pbkdf2_hmac(
        'sha256',
        password.encode('utf-8'),
        salt.encode('utf-8'),
        100000
    )
    return salt, hashed.hex()


def generate_token():
    """Generate a secure random token."""
    return secrets.token_urlsafe(64)


def cleanup_expired_tokens():
    """Remove expired tokens from the store."""
    current_time = time.time()
    expired = [
        token for token, data in tokens_db.items()
        if current_time - data['created_at'] > TOKEN_EXPIRY_SECONDS
    ]
    for token in expired:
        del tokens_db[token]


def token_required(f):
    """Decorator to protect endpoints with token authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None

        # Check for token in Authorization header
        auth_header = request.headers.get('Authorization')
        if auth_header:
            parts = auth_header.split()
            if len(parts) == 2 and parts[0].lower() == 'bearer':
                token = parts[1]

        if not token:
            return jsonify({
                'success': False,
                'message': 'Authentication token is missing. Provide it in the Authorization header as "Bearer <token>".'
            }), 401

        # Clean up expired tokens
        cleanup_expired_tokens()

        # Validate token
        token_data = tokens_db.get(token)
        if not token_data:
            return jsonify({
                'success': False,
                'message': 'Token is invalid or has expired.'
            }), 401

        # Check expiry
        if time.time() - token_data['created_at'] > TOKEN_EXPIRY_SECONDS:
            del tokens_db[token]
            return jsonify({
                'success': False,
                'message': 'Token has expired. Please login again.'
            }), 401

        # Pass the current user to the route
        current_user = token_data['username']
        return f(current_user, *args, **kwargs)

    return decorated


@app.route('/api/register', methods=['POST'])
def register():
    """Register a new user."""
    data = request.get_json()

    if not data:
        return jsonify({
            'success': False,
            'message': 'Request body must be JSON.'
        }), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({
            'success': False,
            'message': 'Username and password are required.'
        }), 400

    if len(username) < 3:
        return jsonify({
            'success': False,
            'message': 'Username must be at least 3 characters long.'
        }), 400

    if len(password) < 8:
        return jsonify({
            'success': False,
            'message': 'Password must be at least 8 characters long.'
        }), 400

    if username in users_db:
        return jsonify({
            'success': False,
            'message': 'Username already exists.'
        }), 409

    salt, hashed_password = hash_password(password)
    users_db[username] = {
        'salt': salt,
        'password_hash': hashed_password,
        'created_at': time.time()
    }

    return jsonify({
        'success': True,
        'message': f'User "{username}" registered successfully.'
    }), 201


@app.route('/api/login', methods=['POST'])
def login():
    """Authenticate user and return a token."""
    data = request.get_json()

    if not data:
        return jsonify({
            'success': False,
            'message': 'Request body must be JSON.'
        }), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')

    if not username or not password:
        return jsonify({
            'success': False,
            'message': 'Username and password are required.'
        }), 400

    user = users_db.get(username)
    if not user:
        # Use constant-time comparison to prevent timing attacks
        # Still hash to keep timing consistent
        hash_password(password, 'dummy_salt_value_1234')
        return jsonify({
            'success': False,
            'message': 'Invalid username or password.'
        }), 401

    salt = user['salt']
    _, hashed_password = hash_password(password, salt)

    if not secrets.compare_digest(hashed_password, user['password_hash']):
        return jsonify({
            'success': False,
            'message': 'Invalid username or password.'
        }), 401

    # Revoke any existing tokens for this user (optional: single session)
    tokens_to_remove = [
        t for t, d in tokens_db.items() if d['username'] == username
    ]
    for t in tokens_to_remove:
        del tokens_db[t]

    # Generate new token
    token = generate_token()
    tokens_db[token] = {
        'username': username,
        'created_at': time.time()
    }

    return jsonify({
        'success': True,
        'message': 'Login successful.',
        'token': token,
        'expires_in': TOKEN_EXPIRY_SECONDS
    }), 200


@app.route('/api/logout', methods=['POST'])
@token_required
def logout(current_user):
    """Logout and invalidate the current token."""
    auth_header = request.headers.get('Authorization')
    token = auth_header.split()[1]

    if token in tokens_db:
        del tokens_db[token]

    return jsonify({
        'success': True,
        'message': 'Logged out successfully.'
    }), 200


