@app.route('/api/change-password', methods=['POST'])
@token_required
def change_password(current_user):
    """Protected endpoint: Change user password."""
    data = request.get_json()

    if not data:
        return jsonify({
            'success': False,
            'message': 'Request body must be JSON.'
        }), 400

    old_password = data.get('old_password', '')
    new_password = data.get('new_password', '')

    if not old_password or not new_password:
        return jsonify({
            'success': False,
            'message': 'Old password and new password are required.'
        }), 400

    if len(new_password) < 8:
        return jsonify({
            'success': False,
            'message': 'New password must be at least 8 characters long.'
        }), 400

    user = users_db[current_user]
    _, old_hash = hash_password(old_password, user['salt'])

    if not secrets.compare_digest(old_hash, user['password_hash']):
        return jsonify({
            'success': False,
            'message': 'Old password is incorrect.'
        }), 401

    # Update password
    new_salt, new_hash = hash_password(new_password)
    users_db[current_user]['salt'] = new_salt
    users_db[current_user]['password_hash'] = new_hash

    # Invalidate all existing tokens for this user
    tokens_to_remove = [
        t for t, d in tokens_db.items() if d['username'] == current_user
    ]
    for t in tokens_to_remove:
        del tokens_db[t]

    return jsonify({
        'success': True,
        'message': 'Password changed successfully. Please login again.'
    }), 200


